// 순차 코드 (Before)
public OrderDetail getOrderDetail(Long orderId) {
    Order order = orderRepository.findById(orderId);
    User user = userService.getUser(order.getUserId());       // 300ms
    Product product = productService.getProduct(order.getProductId()); // 200ms
    return new OrderDetail(order, user, product);
}

public OrderDetail getOrderDetail(Long orderId) {
    Order order = orderRepository.findById(orderId);

    CompletableFuture<User> userFuture = CompletableFuture
        .supplyAsync(() -> userService.getUser(order.getUserId()))
        .orTimeout(2, TimeUnit.SECONDS)
        .exceptionally(ex -> User.unknown());  // Fallback

    CompletableFuture<Product> productFuture = CompletableFuture
        .supplyAsync(() -> productService.getProduct(order.getProductId()))
        .orTimeout(2, TimeUnit.SECONDS)
        .exceptionally(ex -> Product.unknown());  // Fallback

    CompletableFuture.allOf(userFuture, productFuture).join();

    return new OrderDetail(order, userFuture.join(), productFuture.join());
}

// RaceConditionDemo.java
public class RaceConditionDemo {
    private static int counter = 0;

    public static void main(String[] args) throws InterruptedException {
        Runnable task = () -> {
            for (int i = 0; i < 100_000; i++) {
                counter++;  // ← Not atomic!
            }
        };

        Thread t1 = new Thread(task);
        Thread t2 = new Thread(task);
        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Expected: 200000");
        System.out.println("Actual:   " + counter);
        // 실행할 때마다 다른 값 (대부분 200000 미만)
    }
}

// ParallelCallDemo.java
import java.util.concurrent.*;

public class ParallelCallDemo {
    public static void main(String[] args) {
        long start = System.currentTimeMillis();

        // 병렬 호출
        CompletableFuture<String> userFuture = CompletableFuture.supplyAsync(() -> {
            sleep(300);  // user-service 시뮬레이션
            return "User: Alice";
        });

        CompletableFuture<String> productFuture = CompletableFuture.supplyAsync(() -> {
            sleep(200);  // product-service 시뮬레이션
            return "Product: Keyboard";
        });

        CompletableFuture<String> result = userFuture.thenCombine(productFuture,
            (user, product) -> user + " ordered " + product);

        System.out.println(result.join());
        System.out.println("Time: " + (System.currentTimeMillis() - start) + "ms");
        // 예상: ~300ms (순차였다면 500ms)
    }

    private static void sleep(long ms) {
        try { Thread.sleep(ms); } catch (InterruptedException e) { }
    }
}

