// Cache-Aside 구현 (Spring + Redis)
@Service
public class ProductService {

    @Cacheable(value = "products", key = "#id", unless = "#result == null")
    public Product getProduct(Long id) {
        // 캐시 미스 시에만 실행
        return productRepository.findById(id)
            .orElseThrow(() -> new ProductNotFoundException(id));
    }

    @CacheEvict(value = "products", key = "#id")
    public Product updateProduct(Long id, UpdateRequest request) {
        // 데이터 변경 시 캐시 무효화
        Product product = productRepository.findById(id).orElseThrow();
        product.update(request);
        return productRepository.save(product);
    }
}

// Cache-Aside 패턴 — 상품 목록 조회
public List<Product> getProducts(String categoryId) {
    String key = "products:category:" + categoryId;
    // 1) 캐시 확인
    List<Product> cached = redisTemplate.opsForValue().get(key);
    if (cached != null) return cached;          // Cache Hit → DB 접근 없음

    // 2) Cache Miss → DB 조회
    List<Product> products = productRepository.findByCategory(categoryId);

    // 3) 캐시 저장 (TTL 30초)
    redisTemplate.opsForValue().set(key, products, Duration.ofSeconds(30));
    return products;
}

