// Load Shedding — 시스템 부하 기반 비핵심 API 차단
@Component
public class LoadSheddingFilter implements WebFilter {
    private final MeterRegistry metrics;

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, WebFilterChain chain) {
        double cpuUsage = getCpuUsage();
        String path = exchange.getRequest().getPath().value();

        // CPU 85% 초과 시 비핵심 API 거부
        if (cpuUsage > 0.85 && isNonCritical(path)) {
            exchange.getResponse().setStatusCode(HttpStatus.SERVICE_UNAVAILABLE);
            return exchange.getResponse().setComplete();  // 503 즉시 반환
        }
        return chain.filter(exchange);
    }

    private boolean isNonCritical(String path) {
        // 추천, 리뷰, 위시리스트 → 비핵심
        return path.startsWith("/api/recommendations")
            || path.startsWith("/api/reviews")
            || path.startsWith("/api/wishlist");
    }
    // /api/orders, /api/payments → 핵심 (항상 통과)
}

@Service
@Transactional
public class OrderService {

    private final OrderRepository orderRepository;
    private final ProductRepository productRepository;
    private final PaymentService paymentService;  // 직접 주입 (같은 JVM)

    public OrderResponse createOrder(Long userId, CreateOrderRequest request) {
        // 1. 상품 조회 + 재고 검증
        List<OrderItem> items = request.getItems().stream()
            .map(item -> {
                Product product = productRepository.findById(item.getProductId())
                    .orElseThrow(() -> new ProductNotFoundException(item.getProductId()));
                product.decreaseStock(item.getQuantity());  // 재고 감소
                return OrderItem.create(product, item.getQuantity());
            })
            .toList();

        // 2. 주문 생성
        Order order = Order.create(userId, items);
        orderRepository.save(order);

        // 3. 결제 처리 (직접 호출 — 같은 트랜잭션!)
        paymentService.processPayment(order.getId(), order.getTotalAmount());

        // 4. 주문 확정
        order.confirm();

        return OrderResponse.from(order);
    }
    // → 모든 것이 하나의 @Transactional 안에서 처리
    // → 결제 실패 시 주문 + 재고 모두 롤백 (ACID)
    // → MSA에서는 이 방식이 불가능 → Saga 필요 (Step 4)
}

