// payment-service: Consumer 멱등성
@KafkaListener(topics = "order-events", groupId = "payment-group")
public void handleOrderCreated(OrderCreatedEvent event, Acknowledgment ack) {
    if (processedEventStore.isProcessed(event.getEventId())) {
        ack.acknowledge();  // 이미 처리됨
        return;
    }

    PaymentResult result = pgClient.charge(event.getAmount());

    if (result.isSuccess()) {
        kafkaTemplate.send("payment-events",
            event.getOrderId(), new PaymentCompletedEvent(...));
    } else {
        kafkaTemplate.send("payment-events",
            event.getOrderId(), new PaymentFailedEvent(...));
    }

    processedEventStore.markProcessed(event.getEventId());
    ack.acknowledge();
}

