// 아래 코드에서 트랜잭션 경계 문제를 식별하시오.

@Service
public class OrderService {

    @Transactional  // ← 트랜잭션 시작
    public Order createOrder(CreateOrderRequest request) {
        // ① DB 작업: 주문 생성 (5ms)
        Order order = orderRepository.save(new Order(request));

        // ② DB 작업: 재고 차감 (10ms)
        inventoryRepository.decreaseStock(request.getProductId(), request.getQuantity());

        // ③ 외부 API: 결제 PG 호출 (2000ms!) ← 문제!
        PaymentResult result = pgClient.requestPayment(order.getTotalAmount());

        // ④ DB 작업: 결제 정보 저장 (5ms)
        paymentRepository.save(new Payment(order.getId(), result));

        // ⑤ 외부 API: 알림 발송 (500ms) ← 문제!
        notificationClient.sendOrderConfirmation(order);

        return order;
    }
    // 트랜잭션 종료 — 총 DB Connection 점유: ~2520ms!
}

// 개선된 버전은 어떤 구조인가? (정답은 아래 접이식)

@Service
public class OrderService {

    @Transactional  // DB 작업만 트랜잭션
    public Order createOrder(CreateOrderRequest request) {
        Order order = orderRepository.save(new Order(request));
        inventoryRepository.decreaseStock(request.getProductId(), request.getQuantity());
        return order;
    }
    // 트랜잭션 종료 — DB Connection 점유: ~15ms ✅

    // 결제는 트랜잭션 밖에서 (또는 비동기 이벤트)
    public void processPayment(Order order) {
        PaymentResult result = pgClient.requestPayment(order.getTotalAmount());
        paymentRepository.save(new Payment(order.getId(), result));
    }

    // 알림은 비동기 이벤트로 전환
    @EventListener
    @Async
    public void onOrderCreated(OrderCreatedEvent event) {
        notificationClient.sendOrderConfirmation(event.getOrder());
    }
}

