@Service
public class OrderService {
    @Autowired private UserRepository userRepository;
    @Autowired private ProductRepository productRepository;
    @Autowired private OrderRepository orderRepository;

    @Transactional
    public Order createOrder(Long userId, Long productId, int qty) {
        User user = userRepository.findById(userId);       // ← ?
        Product product = productRepository.findById(productId); // ← ?

        user.addPoints(100);  // ← 사용자 포인트 적립 (다른 Aggregate 수정!)
        product.decreaseStock(qty); // ← 재고 차감 (다른 Aggregate 수정!)

        Order order = new Order(user, product, qty); // ← User 객체 직접 참조!
        return orderRepository.save(order);
    }
}

