@Service
public class OrderService {

    private final PaymentClient paymentClient;

    // 어노테이션 기반 (권장)
    @CircuitBreaker(name = "paymentService", fallbackMethod = "paymentFallback")
    @Retry(name = "paymentService")
    @Bulkhead(name = "paymentService")
    @TimeLimiter(name = "paymentService")
    public CompletableFuture<PaymentResult> processPayment(PaymentRequest request) {
        return CompletableFuture.supplyAsync(() ->
            paymentClient.requestPayment(request)
        );
    }

    // Fallback 메서드 (같은 파라미터 + Throwable)
    private CompletableFuture<PaymentResult> paymentFallback(
            PaymentRequest request, Throwable throwable) {

        log.warn("Payment service unavailable, using fallback. Error: {}",
                 throwable.getMessage());

        // 전략 1: 결제 보류 상태로 저장 (나중에 재처리)
        return CompletableFuture.completedFuture(
            PaymentResult.pending("결제 처리가 지연되고 있습니다. 잠시 후 확인해주세요.")
        );
    }
}

