// Domain Event (내부 — 구현 세부사항 포함)
public record OrderCreatedDomainEvent(
    Long orderId,
    Long userId,
    List<OrderItem> items,        // 내부 Entity 직접 참조
    Money totalAmount,             // Value Object
    Address shippingAddress,       // Value Object
    LocalDateTime createdAt,
    String createdBy               // 내부 감사 정보
) {}

// Integration Event (외부 — 최소 정보, 원시 타입)
public record OrderCreatedIntegrationEvent(
    String eventId,                // 멱등성 키
    String eventType,              // "order.created"
    int version,                   // 스키마 버전
    long timestamp,                // Unix timestamp
    OrderCreatedPayload payload
) {}

public record OrderCreatedPayload(
    long orderId,
    long userId,
    long totalAmountCents,         // Money → long (원 단위)
    String currency,               // "KRW"
    int itemCount                  // 상세 항목 대신 수량만
    // shippingAddress, createdBy 제외 (외부에 불필요)
) {}

@Component
public class OutboxPollingPublisher {

    @Scheduled(fixedDelay = 5000)  // 5초 간격
    @Transactional
    public void publishPendingEvents() {
        List<OutboxEvent> events = outboxRepository
            .findByPublishedFalseOrderByCreatedAtAsc(
                PageRequest.of(0, 100));  // 배치 100건

        for (OutboxEvent event : events) {
            try {
                kafkaTemplate.send(
                    "order-events",
                    event.getAggregateId(),  // Partition Key
                    event.getPayload()
                ).get(5, TimeUnit.SECONDS);  // 동기 확인

                event.markPublished();
                outboxRepository.save(event);

            } catch (Exception e) {
                log.error("이벤트 발행 실패: {}", event.getId(), e);
                break;  // 순서 보장을 위해 중단
            }
        }
    }
}

// Kafka Consumer — 읽기 뷰를 구성하는 Projector
@Service
public class OrderViewProjector {

    @KafkaListener(topics = "order-events", groupId = "query-projector")
    public void handleOrderEvent(IntegrationEvent event) {
        switch (event.getEventType()) {
            case "order.created" -> {
                OrderCreatedPayload p = parse(event);
                orderViewRepository.save(new OrderView(
                    p.orderId(),
                    p.userId(),
                    null,  // 고객명은 user 이벤트에서 채움
                    p.totalAmountCents(),
                    "PENDING",
                    p.itemCount()
                ));
            }
            case "order.confirmed" -> {
                orderViewRepository.updateStatus(
                    event.getAggregateId(), "CONFIRMED");
            }
        }
    }

    @KafkaListener(topics = "user-events", groupId = "query-projector")
    public void handleUserEvent(IntegrationEvent event) {
        if ("user.updated".equals(event.getEventType())) {
            UserUpdatedPayload p = parse(event);
            // 해당 사용자의 모든 주문 뷰에 이름 갱신
            orderViewRepository.updateUserName(
                p.userId(), p.name());
        }
    }
}

