@Service
public class OrderService {
    private final OrderRepository orderRepository;
    private final EventPublisher eventPublisher;

    public void cancelOrder(Long orderId, String reason) {
        Order order = orderRepository.findById(orderId)
            .orElseThrow(() -> new OrderNotFoundException(orderId));
        order.cancel(reason);  // PENDING/CONFIRMED만 취소 가능, SHIPPED이면 예외
        orderRepository.save(order);
        eventPublisher.publish(new OrderCancelledEvent(orderId, reason));
    }
}

@ExtendWith(MockitoExtension.class)
class OrderServiceTest {

    @Mock private OrderRepository orderRepository;
    @Mock private EventPublisher eventPublisher;
    @InjectMocks private OrderService orderService;

    @Test
    @DisplayName("PENDING 주문 취소 성공")
    void cancelOrder_pending_success() {
        // given
        Order pendingOrder = OrderFixture.pendingOrder();
        when(orderRepository.findById(5001L))
            .thenReturn(Optional.of(pendingOrder));

        // when
        orderService.cancelOrder(5001L, "고객 변심");

        // then
        assertThat(pendingOrder.getStatus()).isEqualTo(OrderStatus.CANCELLED);
        verify(orderRepository).save(pendingOrder);
        verify(eventPublisher).publish(
            argThat(event -> event instanceof OrderCancelledEvent
                && ((OrderCancelledEvent) event).orderId() == 5001L));
    }

    @Test
    @DisplayName("SHIPPED 주문 취소 시 예외 발생")
    void cancelOrder_shipped_throwsException() {
        // given
        Order shippedOrder = OrderFixture.shippedOrder();
        when(orderRepository.findById(5002L))
            .thenReturn(Optional.of(shippedOrder));

        // when & then
        assertThatThrownBy(() ->
            orderService.cancelOrder(5002L, "고객 변심"))
            .isInstanceOf(IllegalStateException.class)
            .hasMessageContaining("취소");

        verify(orderRepository, never()).save(any());
        verify(eventPublisher, never()).publish(any());
    }
}

// 아래 Money Value Object의 단위 테스트를 작성해보시오.

public record Money(BigDecimal amount, String currency) {

    public Money {
        if (amount.compareTo(BigDecimal.ZERO) < 0)
            throw new IllegalArgumentException("금액은 0 이상이어야 합니다");
        if (currency == null || currency.isBlank())
            throw new IllegalArgumentException("통화는 필수입니다");
    }

    public static Money of(long amount) {
        return new Money(BigDecimal.valueOf(amount), "KRW");
    }

    public Money add(Money other) {
        if (!this.currency.equals(other.currency))
            throw new IllegalArgumentException("통화가 다릅니다");
        return new Money(this.amount.add(other.amount), this.currency);
    }

    public Money multiply(int quantity) {
        return new Money(this.amount.multiply(BigDecimal.valueOf(quantity)), this.currency);
    }
}

/*
테스트 케이스 제안:
1. Money.of(25000) → amount=25000, currency="KRW"
2. Money.of(-1) → IllegalArgumentException
3. KRW + KRW → 합산 성공
4. KRW + USD → IllegalArgumentException (통화 불일치)
5. Money.of(25000).multiply(3) → 75000
6. 두 Money가 같은 값이면 equals = true (Value Object)
*/

