import { Rate, Trend } from "k6/metrics";

// ── 커스텀 메트릭 ──
const errorRate = new Rate("error_rate");
const orderLatency = new Trend("order_latency");

// ── 테스트 설정 ──
export const options = {
  // 시나리오: Load Test (10분)
  stages: [
    { duration: "2m", target: 50 }, // Ramp-up: 2분에 걸쳐 50 VUs
    { duration: "5m", target: 50 }, // Steady: 50 VUs 유지 5분
    { duration: "2m", target: 100 }, // Ramp-up: 100 VUs
    { duration: "3m", target: 100 }, // Steady: 100 VUs 유지
    { duration: "2m", target: 0 }, // Ramp-down: 종료
  ],

  // 성공 기준 (Thresholds)
  thresholds: {
    http_req_duration: [
      "p(50)<200", // P50 < 200ms
      "p(95)<500", // P95 < 500ms
      "p(99)<1000", // P99 < 1000ms
    ],
    error_rate: ["rate<0.01"], // 에러율 < 1%
    http_req_failed: ["rate<0.01"],
  },
};

// ── 테스트 시나리오 ──
export default function () {
  // 1. 상품 목록 조회
  const productsRes = http.get("http://api-gateway:8080/v1/products");
  check(productsRes, {
    "products status 200": (r) => r.status === 200,
  });

  // 2. 주문 생성
  const orderPayload = JSON.stringify({
    userId: Math.floor(Math.random() * 1000) + 1,
    items: [{ productId: 101, quantity: 1 }],
  });

  const orderRes = http.post(
    "http://api-gateway:8080/v1/orders",
    orderPayload,
    { headers: { "Content-Type": "application/json" } },
  );

  check(orderRes, {
    "order status 201": (r) => r.status === 201,
  });

  errorRate.add(orderRes.status !== 201);
  orderLatency.add(orderRes.timings.duration);

  // 사용자 Think Time (실제 사용자 행동 시뮬레이션)
  sleep(Math.random() * 3 + 1); // 1~4초 대기
}

