// ❌ 잘못된 로그
log.info("사용자 가입: email={}, phone={}", user.getEmail(), user.getPhone());
// 출력: 사용자 가입: email=kim@shop.com, phone=010-1234-5678
// → 개인정보 평문 노출! GDPR/개인정보보호법 위반

// ✅ 올바른 로그
log.info("사용자 가입: email={}, phone={}",
    mask(user.getEmail()),    // k***@shop.com
    mask(user.getPhone()));   // 010-****-5678

// 마스킹 유틸
public static String mask(String value) {
    if (value == null) return null;
    if (value.contains("@")) {
        // 이메일: 첫 글자 + *** + @도메인
        int at = value.indexOf("@");
        return value.charAt(0) + "***" + value.substring(at);
    }
    // 전화번호: 가운데 4자리 마스킹
    return value.replaceAll("(\\d{3})\\d{4}(\\d{4})", "$1****$2");
}

