// → 이후 이 스레드의 모든 log.info/error에 correlationId 자동 포함

// HandlerInterceptor.afterCompletion()
MDC.remove("correlationId");  // 스레드 반환 시 정리

// RestClient/WebClient의 RequestInterceptor
String id = MDC.get("correlationId");
request.getHeaders().add("X-Correlation-Id", id);
// → user-service 호출 시 같은 Correlation ID 전달
