# build.gradle
dependencies {
implementation 'org.springframework.boot:spring-boot-starter-actuator'
implementation 'io.micrometer:micrometer-registry-prometheus'
}

@Service
public class OrderService {

    private final MeterRegistry meterRegistry;
    private final Counter orderCreatedCounter;
    private final Timer orderProcessingTimer;

    public OrderService(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;

        // Counter: 주문 생성 수
        this.orderCreatedCounter = Counter.builder("orders.created.total")
            .description("생성된 주문 수")
            .tag("service", "order-service")
            .register(meterRegistry);

        // Timer: 주문 처리 시간
        this.orderProcessingTimer = Timer.builder("orders.processing.duration")
            .description("주문 처리 소요 시간")
            .publishPercentileHistogram()    // P50/P95/P99 자동
            .register(meterRegistry);
    }

    public Order createOrder(CreateOrderRequest request) {
        return orderProcessingTimer.record(() -> {
            // 비즈니스 로직
            Order order = processOrder(request);

            // Counter 증가
            orderCreatedCounter.increment();

            // Gauge: 현재 활성 주문 수 (동적)
            meterRegistry.gauge("orders.active.count",
                orderRepository, repo -> repo.countByStatus(ACTIVE));

            return order;
        });
    }
}

