dependencies {
    implementation 'io.micrometer:micrometer-tracing-bridge-otel'
    implementation 'io.opentelemetry:opentelemetry-exporter-otlp'
}

// Micrometer가 자동으로 Exemplar를 Prometheus 메트릭에 첨부
// Histogram 데이터 포인트에 Trace ID가 포함됨
// Grafana에서 해당 지점 클릭 → Trace로 이동

@Service
public class PaymentService {

    private final ObservationRegistry observationRegistry;

    public PaymentResult processPayment(PaymentRequest request) {
        // 커스텀 Span 생성
        return Observation.createNotStarted("payment.process", observationRegistry)
            .lowCardinalityKeyValue("payment.method", request.getMethod())
            .lowCardinalityKeyValue("payment.currency", request.getCurrency())
            .observe(() -> {
                // PG API 호출 (별도 Span 자동 생성)
                PGResponse pgResponse = pgClient.charge(request);

                // Span에 이벤트 추가
                Observation.Event.of("pg.response.received");

                return PaymentResult.from(pgResponse);
            });
    }
}

# templates/deployment.yaml
apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ .Values.service.name }}
spec:
  replicas: {{ .Values.replicas }}
  selector:
    matchLabels:
      app: {{ .Values.service.name }}
  template:
    metadata:
      labels:
        app: {{ .Values.service.name }}
        version: {{ .Values.image.tag }}
    spec:
      containers:
        - name: {{ .Values.service.name }}
          image: "{{ .Values.image.repository }}:{{ .Values.image.tag }}"
          ports:
            - containerPort: {{ .Values.service.port }}
          resources:
            requests:
              memory: {{ .Values.resources.requests.memory }}
              cpu: {{ .Values.resources.requests.cpu }}
            limits:
              memory: {{ .Values.resources.limits.memory }}
              cpu: {{ .Values.resources.limits.cpu }}
          envFrom:
            - configMapRef:
                name: {{ .Values.service.name }}-config

# main.tf — EKS 클러스터 + RDS (개념)
provider "aws" {
  region = var.region
}

module "eks" {
  source          = "terraform-aws-modules/eks/aws"
  cluster_name    = "${var.project}-${var.env}"
  cluster_version = "1.29"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  eks_managed_node_groups = {
    default = {
      instance_types = [var.node_instance_type]
      min_size       = var.min_nodes
      max_size       = var.max_nodes
      desired_size   = var.desired_nodes
    }
  }
}

module "rds" {
  source = "terraform-aws-modules/rds/aws"

  identifier = "${var.project}-${var.env}-mysql"
  engine     = "mysql"
  engine_version = "8.0"
  instance_class = var.db_instance_class

  allocated_storage = var.db_storage_gb
  db_name           = "orders"
  username          = "admin"
  password          = var.db_password  # Vault에서 주입
}
